import{_ as a,o as t,c as i,a0 as r}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"LESSON_LEARNED_001.md — L1-L4 Batch Generation","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/lessons/LESSON_LEARNED_001.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/lessons/LESSON_LEARNED_001.md","lastUpdated":1783623176000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/lessons/LESSON_LEARNED_001.md"};function n(o,e,l,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="lesson-learned-001-md-—-l1-l4-batch-generation" tabindex="-1">LESSON_LEARNED_001.md — L1-L4 Batch Generation <a class="header-anchor" href="#lesson-learned-001-md-—-l1-l4-batch-generation" aria-label="Permalink to &quot;LESSON_LEARNED_001.md — L1-L4 Batch Generation&quot;">​</a></h1><p><strong>Date:</strong> 12 mar. 2026<br><strong>Lesson:</strong> Batch generation of L1-L4 is the wrong paradigm</p><hr><h2 id="what-happened" tabindex="-1">What Happened <a class="header-anchor" href="#what-happened" aria-label="Permalink to &quot;What Happened&quot;">​</a></h2><p>A pipeline was created to generate L1 (sanitization) for all 4,450 chunks using LLM generation (llama3.2:1b).</p><h3 id="measurements" tabindex="-1">Measurements <a class="header-anchor" href="#measurements" aria-label="Permalink to &quot;Measurements&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Rate</td><td>0.10 items/s</td></tr><tr><td>Time per chunk</td><td>~10 seconds</td></tr><tr><td>ETA for full coverage</td><td>~8 hours</td></tr><tr><td>Timeouts</td><td>Frequent on <code>.rs</code> files</td></tr></tbody></table><h3 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h3><ul><li>Generation via LLM per chunk: <strong>O(n × L)</strong> where n=chunks, L=levels</li><li>Each level requires separate LLM call</li><li>L2 with mistral: 10-50x slower</li><li>L3/L4: would take days</li></ul><h2 id="the-discovery" tabindex="-1">The Discovery <a class="header-anchor" href="#the-discovery" aria-label="Permalink to &quot;The Discovery&quot;">​</a></h2><p>T-RAG (G5) works with <strong>L0 + T4 only</strong>. Higher levels (L1-L4) are optional.</p><h3 id="proof" tabindex="-1">Proof <a class="header-anchor" href="#proof" aria-label="Permalink to &quot;Proof&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/trag_query.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;nexus architecture&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#01 [score=0.93] L0 — relevant result</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#02 [score=0.57] L0 — relevant result</span></span></code></pre></div><p><strong>The system retrieves relevant content without L1-L4.</strong></p><h2 id="why-batch-generation-is-wrong" tabindex="-1">Why Batch Generation is Wrong <a class="header-anchor" href="#why-batch-generation-is-wrong" aria-label="Permalink to &quot;Why Batch Generation is Wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Problem</th></tr></thead><tbody><tr><td>Proactive generation</td><td>Generates everything, uses nothing</td></tr><tr><td>Per-chunk LLM</td><td>O(n) calls, expensive</td></tr><tr><td>Lazy evaluation</td><td>Generate only when context fills</td></tr></tbody></table><h2 id="the-correct-paradigm" tabindex="-1">The Correct Paradigm <a class="header-anchor" href="#the-correct-paradigm" aria-label="Permalink to &quot;The Correct Paradigm&quot;">​</a></h2><p><strong>Lazy + On-Demand Generation</strong></p><ol><li>L0 is always available (embeddings)</li><li>T4 provides topological context (PPR weights)</li><li>L1-L4 generated <strong>only when needed</strong>: <ul><li>When context window fills</li><li>When query requires synthesis</li><li>When specific abstraction is requested</li></ul></li></ol><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>&gt; <strong>T-RAG works with L0 + T4 only. L1-L4 are for memory pagination use cases, not batch processing.</strong></p><p>This is not a bug — it&#39;s an architectural clarification. The system works. The batch pipeline was unnecessary.</p><h2 id="files-affected" tabindex="-1">Files Affected <a class="header-anchor" href="#files-affected" aria-label="Permalink to &quot;Files Affected&quot;">​</a></h2><ul><li><code>scripts/l1_sanitization.py</code> — stopped (wrong paradigm)</li><li><code>scripts/l2_abstraction.py</code> — not executed (would be same issue)</li><li><code>docs/experiments/EXPERIMENTO_01_BASELINE_L1.md</code> — baseline measurement</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><ul><li>✅ T-RAG operational with L0 + T4</li><li>✅ L1 exists but not required</li><li>✅ Meta-query layer works</li><li>⚠️ L1-L4 batch generation deprecated</li></ul>`,26)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
